CREATE OR REPLACE FUNCTION fpa_lon_divide_req_no (adt_bdate timestamp(0) , adt_edate timestamp(0) , as_loan_type char) RETURNS varchar AS $body$
DECLARE

 li_count integer;
 li_count_n integer;
 ls_reqno varchar(400);
 ls_reqno_min sc_lon_m_loan_request.loan_requestment_no%type;
 ls_reqno_max sc_lon_m_loan_request.loan_requestment_no%type;


 type tabrowi_reqno is table of sc_lon_m_loan_request%rowtype index by integer;
 ltabrowi_reqno tabrowi_reqno;
 ltabrowi_reqno_n tabrowi_reqno;


BEGIN
  begin
    select	min(sc_lon_m_loan_request.loan_requestment_no) , max(sc_lon_m_loan_request.loan_requestment_no)
    into STRICT    ls_reqno_min , ls_reqno_max
    from		sc_lon_m_loan_request
        ,	sc_mem_m_membership_registered
        ,	sc_mem_m_ucf_member_group
        ,	sc_lon_m_rule
        ,	sc_mem_m_ucf_coop_control
    where (sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_request.membership_no)
    and (sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no)
    and (sc_lon_m_rule.loan_type	=	sc_lon_m_loan_request.loan_type)
    and (sc_mem_m_ucf_coop_control.control_id = sc_mem_m_ucf_member_group.control_id)
    and (sc_lon_m_loan_request.flag_status = '00')
    and (sc_lon_m_loan_request.loan_requestment_no <>  upper('CNV'))
    and (sc_lon_m_loan_request.cancel_status = '0')
    and (sc_lon_m_loan_request.requestment_date BETWEEN adt_bdate and adt_edate)
    and (sc_lon_m_loan_request.loan_type = as_loan_type);
    exception
    when others then CALL spa_dberror('E35 : select max , min reqno');
  end;

    select  * bulk collect into STRICT ltabrowi_reqno_n
    from    sc_lon_m_loan_request
    where (requestment_date BETWEEN adt_bdate and adt_edate)
    and (loan_type = as_loan_type)
    and (sc_lon_m_loan_request.flag_status = '01')
    order by loan_requestment_no;

    li_count_n := ltabrowi_reqno_n.count;

    if li_count_n > 1 then
     for i in 1..li_count loop
       --ตรวจสอบดูเลขที่เรียงกันด้วย
      if (ltabrowi_reqno_n[li_count_n - 1].loan_requestment_no + 1) <> (ltabrowi_reqno_n[li_count_n].loan_requestment_no) then
        ls_reqno := ls_reqno|| ' , '||(ltabrowi_reqno_n[li_count_n - 1].loan_requestment_no + 1) ||' - '|| (ltabrowi_reqno_n[li_count_n].loan_requestment_no - 1);
      else
        ls_reqno := ls_reqno;
      end if;

     end loop;
      ls_reqno := ls_reqno_min||ls_reqno||ls_reqno_max;
    else
      ls_reqno := ls_reqno_min || ' - '||(ltabrowi_reqno_n[1].loan_requestment_no - 1)||' , '
                  ||(ltabrowi_reqno_n[1].loan_requestment_no + 1)||' - '||ls_reqno_max;
    end if;


END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
